import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        for __ in range(M):
            next(it); next(it)  # skip a_i, b_i
        for i in range(1, N):
            out_lines.append(' '.join(['1'] * (N - i)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

