const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(data[idx++]);
  const M = Number(data[idx++]);
  for (let i = 0; i < M; i++) { idx += 2; } // skip flips
  for (let i = 1; i < N; i++) {
    const line = Array(N - i).fill('1').join(' ');
    output.push(line);
  }
}
